import { Component, OnInit, computed, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { ManagedUser } from '../../core/models';
import { AdminApiService } from '../../core/services/admin-api.service';
import { ToastService } from '../../core/services/toast.service';

@Component({
  selector: 'app-moderation',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './moderation.component.html',
  styleUrl: './moderation.component.css',
})
export class ModerationComponent implements OnInit {
  private admin = inject(AdminApiService);
  private toast = inject(ToastService);

  readonly users = signal<ManagedUser[]>([]);

  readonly totalUsers = computed(() => this.users().length);
  readonly bannedCount = computed(() => this.users().filter((u) => u.banned).length);
  readonly flaggedCount = computed(() => this.users().filter((u) => u.reports > 0 && !u.banned).length);

  ngOnInit(): void {
    this.admin.users().subscribe({
      next: (users) => this.users.set(users ?? []),
      error: () => this.users.set([]),
    });
  }

  ban(user: ManagedUser): void {
    this.admin.ban(user.id).subscribe({
      next: () => {
        this.users.update((list) => list.map((u) => (u.id === user.id ? { ...u, banned: true } : u)));
        this.toast.push('message', 'User banned', `${user.name} has been removed and logged out.`);
      },
      error: () => {},
    });
  }

  unban(user: ManagedUser): void {
    this.admin.unban(user.id).subscribe({
      next: () => {
        this.users.update((list) => list.map((u) => (u.id === user.id ? { ...u, banned: false } : u)));
      },
      error: () => {},
    });
  }
}
